INSERT INTO exercise_categories (name) VALUES
  ('Legs'),
  ('Arms'),
  ('Core'),
  ('Back & Neck'),
  ('Cardio'),
  ('Medicine Ball');
INSERT INTO exercises (name, instructions, muscle_groups, category_id, is_public) VALUES
  ('Squat Jumps', 'Explosive squat jumps are great for working on power. Squat down low and jump upwards with all your power raising your arms as high as you can. Think of yourself as a spring loading. When you jump flex your feet upwards to further activate your quads.', '{Quads,Glutes,Calves}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Sumo Squats', 'Have your feet wider than shoulder width apart with your toes pointing slightly out. Sit back with your hips first and then bend your knees. Keep your chest up and look straight ahead. If you cannot get low due to poor ankle mobility elevate your heels using a plate.', '{Quads,Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Squats', 'The goal is to get as low as possible while maintaining form. Your feet should be shoulder width apart or a little wider. Your knees should not go over your toes. Sit back with your hips first and then bend your knees. Keep your chest up and look straight ahead. If you cannot get low due to poor ankle mobility elevate your heels using a plate.', '{Quads,Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Front Squats', 'Rest the barbell on your collar bones -- there should be no weight on your wrists. Keep your elbows up pointing at the wall in front of you.', '{Quads,Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Goblet Squat', 'The goal is to get as low as possible while maintaining form. Your feet should be shoulder width apart and square. Sit back with your hips first and then bend your knees. Keep your chest up and look straight ahead. Hold the weight at your chest.', '{Quads,Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Single Leg Squats', 'Make sure your knee and ankle are in line. Your leg should be at a 90 degree angle and your knee should not go past your toes.', '{Quads,Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Bulgarian Split Squats', 'Elevate your back leg on a chair or bench. Make sure your toes are pointing forward and your knee is not going over your toe.', '{Quads,Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Bulgarian Split Squats With Front Foot Elevated', 'Elevate your back leg on a chair or bench. Make sure your toes are pointing forward and your knee is not going over your toe. Elevate your front foot at the height of your choice. The higher the elevation the deeper the squat.', '{Quads,Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Split Squats', 'Make a 90 degree angle with your legs. Make sure your legs aren''''t too wide or too narrow.', '{Quads,Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Clean', 'Start with a light weight. Your legs should be doing most of the work. The bar should NOT swing and maintain a straight path. After the pull phase you rotate your arms around the bar, you are NOT rotating the bar.', '{Quads,Hamstrings,Glutes,Traps}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Overhead Squat', 'Your feet should be shoulder width apart and square. Your knees should not go over your toes. Sit back with your hips first and then bend your knees. Keep your chest up and look straight ahead. Keep your arms as straight over your head as possible.', '{Quads,Glutes,Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Squat Hold', 'Your feet should be shoulder width apart and square. Your knees should not go over your toes. Sit back with your hips first and then bend your knees. Keep your chest up. Your knees should be bent at about a 90 degree angle.', '{Quads,Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Prisoner Squat', 'Your feet should be shoulder width apart and square. Your knees should not go over your toes. Sit back with your hips first and then bend your knees. Keep your chest up. Interlock your hands behind your head.', '{Quads,Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Burpees', 'Start by jumping up and landing on your hands and feet as softly as possible. Then push yourself up with your hands, bring your feet in, and then jump. To modify: four count burpee (no push-up). To make it harder: up down burpee.', '{Full Body,Quads,Chest}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('4-Count Burpee', 'Start by jumping up and landing on your hands and feet as softly as possible. Then push yourself up with your hands, bring your feet in, and then jump. This does not require a push-up.', '{Full Body,Quads}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Push-up Burpee', 'Start by jumping up and landing on your hands and feet as softly as possible. Perform a regular push-up. Then push yourself up with your hands, bring your feet in, and then jump.', '{Full Body,Quads,Chest}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Tuck Jump Burpee', 'Start by jumping up and landing on your hands and feet as softly as possible. Then push yourself up with your hands, bring your feet in, and then do a tuck jump.', '{Full Body,Quads}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Bridges', 'Keep your feet flat on the floor and your heels as close to your butt as possible. Lift your toes up and explode up through your heels. Pause for 3 seconds at the top. To make it more difficult: dumbbell across your pelvis, ball between your knees, or use a band.', '{Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Kettlebell Deadlift', 'Keep a flat back and push your hips back. Then sit your hips down like you are about to sit in a chair. The kettlebell should end up directly in line with your heels.', '{Hamstrings,Glutes,Lower Back}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Trap Bar Deadlift', 'Keep a flat back and your shoulders back. Push with your legs, don''''t yank the bar with your arms.', '{Hamstrings,Glutes,Lower Back,Quads}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Hamstring Slides', 'Place carpets or sliders under your heels, start as close to your butt as possible. Start in a bridge position, extend your legs then bring them close to your butt again while maintaining the bridge.', '{Hamstrings,Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Bridge Hold', 'Keep your feet flat on the floor and your heels as close to your butt as possible. Lift your toes up and raise your hips up so they are in a neutral position.', '{Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Barbell Hip Thrusts', 'Keep your feet flat on the floor and drive through your heels. Lift your toes up and raise your hips up so they are in a neutral position.', '{Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Single Leg Bridge', 'Keep your foot flat on the floor and your heel as close to your butt as possible. Your other foot should be straight in the air. Lift your toes up and explode up through your heel. Pause for 3 seconds at the top.', '{Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Good Mornings', 'ONLY BEND AT THE HIPS. Do not go below parallel. Have your knees bent slightly so they are not locked. Hug the weight. Make sure your back, neck, and head are all in line.', '{Hamstrings,Lower Back,Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('RDLs', 'Have your knees locked at a soft bend, keep your back flat, and push your hips back. Only go as deep as your hamstrings let you. Make sure your back, neck, and head are all in line.', '{Hamstrings,Glutes,Lower Back}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Single Leg RDLs', 'ONLY BEND AT THE HIPS. Do not go below parallel. Have your knee planted on the ground bent slightly so it is not locked. Make sure your back, neck, and head are all in line.', '{Hamstrings,Glutes,Lower Back}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Lunges', 'Do not step too far out. Keep your knees, ankle, and toes all in line. You should be making a 90 degree angle.', '{Quads,Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Reverse Lunges', 'Do not step too far back. Keep your knees, ankle, and toes all in line. You should be making a 90 degree angle.', '{Quads,Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Lateral Lunge', 'Do not step too far sideways. Keep your hip, knees, ankle, and toes all in line.', '{Quads,Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Walking Lunges', 'Do not take too large of a step, your knee should never come over your foot, and each step should make a 90 degree angle. Keep your chest up.', '{Quads,Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Jumping Lunges', 'Keep your knees, ankle, and toes all in line. You should be making a 90 degree angle every jump. Add some weight for more of a challenge.', '{Quads,Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Pendulum Lunges', 'Go from a forward lunge straight into a backward lunge. No breaks in between. Each step should make a 90 degree angle.', '{Quads,Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Wall Sit', 'Your feet should be shoulder width apart and square. Your knees should not go over your toes. Keep your chest up and look straight ahead. Your back should be flat against the wall. Pretend you are sitting in a chair.', '{Quads,Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Skaters', 'Keep your knee, ankle, and foot all in line. Your knee should not come over your foot. Try to have a slight pause before switching direction. Jump as far horizontal as possible while staying low to the ground.', '{Quads,Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Broad Jump', 'Try to jump as far out as you can. When you are dropping down to a squat think of it as loading a spring that is going to spring horizontal.', '{Quads,Glutes,Calves}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Tuck Jumps', 'Stay on the balls of your feet, jump up, and bring your knees to waist height.', '{Quads,Calves}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Box Jumps', 'Use your arms to help give you some exploding power to jump higher. Try to land softly on the balls of your feet. Do not let your knees go over your toes if possible.', '{Quads,Glutes,Calves}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Calf Raises', 'More beneficial when the balls of your feet are placed on a step, plate, or box. Going past parallel allows you to better target the calf muscles.', '{Calves}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Kettlebell Swings', 'Your feet should be shoulder width apart or a little wider. When loading into the swing sit back with your hips first and then bend your knees. Then stand up and thrust your hips forward.', '{Glutes,Hamstrings,Lower Back}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Clam Shells', 'These work best with a band around the top of your knees. If you do not have a band try holding a dumbbell near your knee.', '{Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Donkey Kick Pulses', 'Start in a quadruped position with your hands under your shoulders and knees under your hips. Keeping your knee at 90 degrees bring one foot towards the sky. Try to maintain equal weight on all 3 limbs and do not shift your hips.', '{Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Lateral Step Down', 'Just like a squat go back with your hips before you bend your knee. Try not to let your knee come over your toes. Use a higher step or add more weight to make it more difficult.', '{Quads,Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Depth Drops', 'Start with your hips, knees, and arms extended. Step off the box and land on the ball of your foot with your feet shoulder width apart. Land with soft knees and your hips back, try not to let your knees cave in or out.', '{Quads,Glutes,Calves}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Banded Lateral Walks', 'Place a band just above your knees. Get as low as possible while maintaining form. Your knees should not go over your toes. Sit back with your hips first then bend your knees. Keep your chest up. Do not click your heels.', '{Glutes,Quads}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Dumbbell Snatch', 'Start in a squatting position. Have a palms down grip on the dumbbell. Stand up using the force of your legs and as soon as the dumbbell is about hip height pull it into an overhead position.', '{Quads,Glutes,Shoulders,Traps}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Step-Ups', 'Put all your weight on the foot on the box or stair. Use the foot to drive your body upward. Make sure your knee does not go over your toes. The foot off the box should be straight, your ankle neutral, and your toes pointing up.', '{Quads,Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Quick Feet', 'Try to stay as low to the ground as you can in an athletic stance the whole time. Stay on the balls of your feet with your toes up. Pretend the ground is hot and pick your feet up as fast as possible.', '{Quads,Calves}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Power Jacks', 'Perform a jumping jack but instead of jumping up go into a squat.', '{Quads,Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Pogos for Speed', 'Try not to bend your knees to assist with the jump -- only use the force of your calves. Stay on the balls of your feet and keep your toes up. Move your arms as fast as possible.', '{Calves}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Pogos for Height', 'Try not to bend your knees to assist with the jump, only use the force of your calves. Stay on the balls of your feet and keep your toes up. The goal is to get as high as possible.', '{Calves}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Curtsy Lunge', 'Try not to step too wide. Keep your knee as straight and stable as possible.', '{Quads,Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Pulse Squat', 'The goal is to get as low as possible while maintaining form and not coming fully up. Your knees should not go over your toes. Sit back with your hips first then bend your knees. Keep your chest up.', '{Quads,Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Leg Press - High Foot Placement', 'Focuses on glutes and hamstrings. Do not lock your knees when you extend.', '{Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Leg Press - Low Foot Placement', 'Focuses on the quads. Do not lock your knees when you extend.', '{Quads}', (SELECT id FROM exercise_categories WHERE name = 'Legs'), true),
  ('Lateral Raises', 'Have your arms slightly bent at the elbows. When you raise your arms think of the dumbbells as buckets of water you''''re trying to pour.', '{Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Overhead Press', 'Try to not drop your arms past parallel. Focus on squeezing your shoulder blades back a little.', '{Shoulders,Triceps}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Tricep Kickback', 'Knees should be slightly bent, hips back so your chest is pointed at the floor, back flat not rounded, and your arm should be close to your body with your elbow bent at 90 degrees with a neutral grip.', '{Triceps}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Pushups', 'Place your hands under your shoulders, maintain a flat back, and do not let your hips sink. When bending your arms make sure your elbows are close to your body. If regular pushups are too hard try going on your knees.', '{Chest,Triceps,Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Wide Pushups', 'Place your hands a little wider than your shoulders, maintain a flat back, and do not let your hips sink.', '{Chest,Triceps,Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Diamond Pushup', 'Place your hands directly under your chest. Spread your thumb and index finger out so they are making a diamond.', '{Triceps,Chest}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Tricep Push-up', 'Place your hands closer to your body than a regular pushup, maintain a flat back, and do not let your hips sink. When bending your arms make sure your elbows are close to your body.', '{Triceps,Chest}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Chest Press', 'Keep your back flat on the bench, do not arch. Have your feet flat on the floor. Grip the bar a thumb''''s length away from where the rough and smooth part touch.', '{Chest,Triceps,Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Incline Chest Press', 'Incline the bench to 35-45 degrees.', '{Chest,Triceps,Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Chest Fly', 'Start light and do not go beyond parallel.', '{Chest}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Skullcrushers', 'Keep your arms parallel with your elbows. Do not let your elbows flair out or in.', '{Triceps}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Tricep Dips', 'Place your hands on an elevated surface and your feet straight out. Bend your elbows until you''''re at about a 90 degree angle or a little below. Then straighten your arms all the way up.', '{Triceps,Chest}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Chin Ups', 'When doing a chin up you want the front of your hands facing you. You want to get your chin over the bar. Modify with a chip assist machine or a band.', '{Biceps,Lats,Back}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Pull Ups', 'When doing a pull up you want the back of your hands facing you. You want to get your chin over the bar. Modify with a chip assist machine or a band.', '{Lats,Back,Biceps}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Inverted Row', 'Lay underneath the bar and have a palms up grip. To make it more difficult keep your legs straight, to make it easier bend your knees. Pull up to about the bottom of your sternum.', '{Back,Biceps,Lats}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Upright Row', 'Try not to raise your arms past your armpits.', '{Shoulders,Traps,Biceps}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Pike Pushups', 'The closer your hands are to your feet the harder it will be. Modify to a regular pushup if too challenging.', '{Shoulders,Triceps}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Floor Press', 'Lay on the ground and use the same form you would for a bench press.', '{Chest,Triceps,Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Farmer''''s Carry', 'Stay as straight as possible not leaning to one direction. Squeeze your core and walk slow.', '{Traps,Rectus Abdominis}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Inchworm', 'Walk out until you are in a high plank position with your hands directly under your shoulders.', '{Shoulders,Hamstrings,Rectus Abdominis}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Inchworm Pushups', 'Walk out until you are in a high plank position with your hands where they would be for pushups. After the pushups walk your hands back and stand up.', '{Chest,Triceps,Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Shoulder Taps', 'Try to hold a high plank as still as possible while tapping your shoulders. If this is too difficult try it on your knees.', '{Shoulders,Rectus Abdominis}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Banded Internal and External Rotation', 'Place a rolled up towel between your arm and side right around the elbow. This will keep your arm in place allowing you to isolate the rotations.', '{Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Scapular Pull Ups', 'Get started in a pull up position, palms facing away from you. Without using your arms pull yourself up using your shoulder blades.', '{Back,Lats}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Bicep Curls', 'Keep each motion slow and controlled. Make sure to focus on squeezing your bicep at the top.', '{Biceps}', (SELECT id FROM exercise_categories WHERE name = 'Arms'), true),
  ('Planks', 'Place your elbows under your shoulders and keep a flat back. Look forward to keep your neck and upper back straight. You want to lift your shoulders as high as possible and pull your hip/stomach in while staying flat.', '{Rectus Abdominis}', (SELECT id FROM exercise_categories WHERE name = 'Core'), true),
  ('Side Planks', 'Go on your side and make sure your elbow is directly under shoulder. Legs should be straight. Put your other arm straight in the air or on your hip.', '{Obliques,Rectus Abdominis}', (SELECT id FROM exercise_categories WHERE name = 'Core'), true),
  ('Mountain Climbers', 'Start in a plank position and drive your knees to your elbows as fast as you can. Try to keep your back as flat as possible.', '{Rectus Abdominis,Quads}', (SELECT id FROM exercise_categories WHERE name = 'Core'), true),
  ('Sit Ups', 'Keep your feet flat on the floor and your heels as close to your butt as possible. Recommend having someone hold your feet or put your feet under a couch. To make it more difficult use a dumbbell.', '{Rectus Abdominis}', (SELECT id FROM exercise_categories WHERE name = 'Core'), true),
  ('Crunches', 'Lay on your back with your feet elevated. Put your hands on your head and try to have your elbows touch your knees when you crunch. Make sure your neck is stable and is not moving.', '{Rectus Abdominis}', (SELECT id FROM exercise_categories WHERE name = 'Core'), true),
  ('Russian Twists', 'Put your hands together and turn to each side. Really focus on just twisting your obliques and not your whole body. To make it more difficult add some weight.', '{Rectus Abdominis,Obliques}', (SELECT id FROM exercise_categories WHERE name = 'Core'), true),
  ('Bicycle Crunches', 'Try to keep your neck stable, do not bend it. Squeeze your abs to bring your opposite elbow to your opposite knees.', '{Rectus Abdominis,Obliques}', (SELECT id FROM exercise_categories WHERE name = 'Core'), true),
  ('Dead Bugs', 'Lay on your back with your legs and hips bent at 90 degrees. Raise both arms straight in front of you. Extend your opposite arm and opposite leg, then return to the starting position.', '{Rectus Abdominis}', (SELECT id FROM exercise_categories WHERE name = 'Core'), true),
  ('Hollow Body Hold', 'Make sure your lower back is touching the ground. Keep your feet about 6 inches above the ground.', '{Rectus Abdominis}', (SELECT id FROM exercise_categories WHERE name = 'Core'), true),
  ('V Sit Ups', 'Lay on your back and fold your body in half. Have your toes and hands meet halfway. Keep all your limbs as straight as possible.', '{Lower Core}', (SELECT id FROM exercise_categories WHERE name = 'Core'), true),
  ('Hanging Leg Raises', 'Bring your knees up as high as you can. DO NOT SWING. Keep the motion controlled for the best ab workout.', '{Lower Core}', (SELECT id FROM exercise_categories WHERE name = 'Core'), true),
  ('Ab Rollout', 'Get as close to the ground as possible when rolling out. When you roll back come all the way back and touch your legs.', '{Rectus Abdominis,Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Core'), true),
  ('Leg Lifts', 'DO NOT DO THESE IF YOU HAVE LOWER BACK PAIN! Try to keep your lower back flat on the floor.', '{Lower Core}', (SELECT id FROM exercise_categories WHERE name = 'Core'), true),
  ('Flutter Kicks', 'Lean back on your arms to support you and straighten your legs. Move one leg up and one leg down.', '{Lower Core}', (SELECT id FROM exercise_categories WHERE name = 'Core'), true),
  ('Scissor Kicks', 'Lean back on your arms to support you and straighten your legs. Move your legs towards each other so that they cross.', '{Lower Core}', (SELECT id FROM exercise_categories WHERE name = 'Core'), true),
  ('Reverse Crunch', 'Raise both legs straight up then perform a reverse crunch. Think of your legs having a string attached that pulls them straight up.', '{Lower Core}', (SELECT id FROM exercise_categories WHERE name = 'Core'), true),
  ('High Plank', 'Place your hands under your shoulders, maintain a flat back, and do not let your hips sink.', '{Rectus Abdominis,Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Core'), true),
  ('High Plank Knee to Elbow', 'Get in a high plank position. Bring your knee to your opposite elbow.', '{Rectus Abdominis,Obliques}', (SELECT id FROM exercise_categories WHERE name = 'Core'), true),
  ('Copenhagen Plank', 'Get in a side plank position then put the opposite leg on a bench or chair. If too difficult start by putting more of your leg on the chair.', '{Obliques,Rectus Abdominis}', (SELECT id FROM exercise_categories WHERE name = 'Core'), true),
  ('Windshield Wipers', 'Keep your legs as straight as possible. Try to move slow and controlled. To modify bend your knees.', '{Rectus Abdominis,Obliques}', (SELECT id FROM exercise_categories WHERE name = 'Core'), true),
  ('Leg Circles', 'Lay on your back with your legs up. Move your legs in a slow and controlled circle. Put your hands underneath your butt if it makes it more comfortable.', '{Rectus Abdominis}', (SELECT id FROM exercise_categories WHERE name = 'Core'), true),
  ('6 Inches and Hold', 'Make sure your lower back is touching the ground. Keep your feet about 6 inches above the ground.', '{Rectus Abdominis}', (SELECT id FROM exercise_categories WHERE name = 'Core'), true),
  ('Side Plank Dips', 'Your arm should be directly under your shoulder with both feet straight. Slowly bring your hip to the ground then back to the starting position.', '{Obliques,Rectus Abdominis}', (SELECT id FROM exercise_categories WHERE name = 'Core'), true),
  ('Toe Touches', 'Try to keep your feet raised as straight as possible. Touch your hands to your feet. To make this more difficult add some weight.', '{Rectus Abdominis}', (SELECT id FROM exercise_categories WHERE name = 'Core'), true),
  ('Plank Rotations', 'Start and end every rep in a low plank or high plank position. Rotate until your arm is straight up into the air.', '{Rectus Abdominis,Obliques}', (SELECT id FROM exercise_categories WHERE name = 'Core'), true),
  ('Knee Tuck Crunches', 'Sit in a position as if you were going to do Russian twists. Straighten your legs and lean back. Then bend your legs and bring your body up to the starting position.', '{Rectus Abdominis}', (SELECT id FROM exercise_categories WHERE name = 'Core'), true),
  ('Supermans', 'Lay on your stomach and raise both your legs and arms at the same time. Pause for a few seconds at the top. Try to keep your head movement at the same level as your arms.', '{Lower Back,Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('Superman Holds', 'Lay on your stomach, raise both your legs and arms at the same time, and hold. Try to keep your head movement at the same level as your arms.', '{Lower Back,Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('Single Arm Superman', 'Lay on your stomach and lift your opposite arm and leg at the same time. Pause at the top then switch to the other arm and leg.', '{Lower Back,Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('Bent Over Row', 'Have your knees slightly bent and your back flat while bending forward at the hip to get as close to parallel to the ground as possible.', '{Back,Lats,Biceps}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('Cable Row', 'Let your shoulders go all the way forward then start by squeezing your shoulder blades back before pulling the weight.', '{Back,Lats,Biceps}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('WXYs', 'Really exaggerate the movement and squeeze your shoulder blades back. Try adding some weight to make it more difficult.', '{Back,Shoulders,Traps}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('ITYs', 'Really exaggerate the movement and squeeze your shoulder blades back. Try adding some weight to make it more difficult.', '{Back,Shoulders,Traps}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('Superman Pull', 'Lay on your stomach, raise both your legs and arms at the same time. Bend your arms and bring them back. Really exaggerate squeezing your shoulder blades back.', '{Lower Back,Back,Traps}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('Back Extensions', 'Start with a low weight and work your way up. Make sure to get a full range of motion.', '{Lower Back,Glutes,Hamstrings}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('Lying Lat Pull', 'Lay on your stomach, raise both arms at the same time then bend your arms and bring them back. Really exaggerate squeezing your shoulder blades back.', '{Lats,Back}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('Chin Tuck Neck Lifts', 'Lay on your back in a neutral position. Tuck your chin to your chest. Lift your head up 1/2 inch off the ground (THIS IS A VERY MINOR MOVEMENT). Slowly lower your head back to the ground and untuck your chin.', '{Lower Back}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('Supine Lumbar Rotations', 'Lay on your back with your hips and knees at 90 degrees. Straighten arms so you look like a T, bring your legs to the side as far as you can with the goal of them touching the ground then return to the middle.', '{Lower Back}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('Prone X', 'Lay on your stomach, raise both your legs and arms at the same time like a superman, then spread your arms and legs. Pause then return to the starting position.', '{Lower Back,Traps}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('Prone I to T', 'Lay on your stomach, raise both your legs and arms like a superman, then spread your arms apart until your body is making a T. Pause then return your arms to a superman position.', '{Lower Back,Traps,Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Back & Neck'), true),
  ('Agility Ladder', 'Stay on the balls of your feet. Move your arms as if you are running. Get your feet off the ground as quick as possible.', '{Full Body,Calves}', (SELECT id FROM exercise_categories WHERE name = 'Cardio'), true),
  ('Rower Machine', 'Legs move first then back then hips then pull. Make sure feet are secured. You want a long pull not short ones.', '{Full Body,Back,Lats}', (SELECT id FROM exercise_categories WHERE name = 'Cardio'), true),
  ('Jump Rope', 'Go as fast as possible. If you mess up that is okay just restart immediately. To make it more challenging use a weighted jump rope.', '{Calves,Full Body}', (SELECT id FROM exercise_categories WHERE name = 'Cardio'), true),
  ('Seal Jacks', 'Only have your feet go as wide as they would for a jumping jack. Open your arms up all the way so you really feel your shoulder blades go back.', '{Shoulders,Full Body}', (SELECT id FROM exercise_categories WHERE name = 'Cardio'), true),
  ('Med Ball Push-Up', 'Start with normal push-up hand positioning but place the medicine ball under one of your hands. Complete a push-up then roll the ball to the other arm.', '{Chest,Triceps,Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Medicine Ball'), true),
  ('Medicine Ball Chop Slams', 'Emphasize turning to one side like a Russian twist before you slam the ball. Quickly pick the ball up and turn to the opposite side and throw the ball down as hard as you can.', '{Rectus Abdominis,Obliques,Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Medicine Ball'), true),
  ('Medicine Ball Slams', 'Start in triple extension and throw the ball down as hard as you can. Quickly pick the ball up in a squat form. For your first time choose a weight no more than 10% of your body weight.', '{Full Body,Rectus Abdominis,Shoulders}', (SELECT id FROM exercise_categories WHERE name = 'Medicine Ball'), true),
  ('Medicine Ball Sumo Squat', 'Have a wide base (feet more than shoulder width apart) with feet angled outwards. Sit into the squat making sure your knees do not go over your toes. Hold the medicine ball at chest height.', '{Quads,Glutes}', (SELECT id FROM exercise_categories WHERE name = 'Medicine Ball'), true),
  ('Medicine Ball RDLs', 'ONLY BEND AT THE HIPS. Do not go below parallel. Have your knees bent slightly so they are not locked. Keep your arms straight. Make sure your back, neck, and head are all in line.', '{Hamstrings,Glutes,Lower Back}', (SELECT id FROM exercise_categories WHERE name = 'Medicine Ball'), true),
  ('Medicine Ball Russian Twists', 'Lean back on your tail bone with your feet off the floor. Hold the ball and turn to each side. Really focus on just twisting your obliques and not your whole body.', '{Rectus Abdominis,Obliques}', (SELECT id FROM exercise_categories WHERE name = 'Medicine Ball'), true),
  ('Medicine Ball Toe Touches', 'Try to keep your feet raised as straight as possible. Touch the ball to your feet. To make this more difficult use a heavier ball.', '{Rectus Abdominis}', (SELECT id FROM exercise_categories WHERE name = 'Medicine Ball'), true);